proof fn phi_1_always_to_current_intensional_bridge(ex: Execution<int>, p: TempPred<int>)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex),
{
    always_to_current::<int>(ex, p);
}

proof fn phi_2_temp_pred_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p == q,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_3_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_4_and_always_idempotent_equality(p: TempPred<int>)
    ensures
        p.and(always(p)) == always(p),
{
    p_and_always_p_equals_always_p::<int>(p);
}

proof fn phi_5_always_to_current_at_suffix(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex.suffix(i)),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_to_current::<int>(ex.suffix(i), p);
}
